                <span class="title-volume badge ${t.search_volume}">${t.search_volume} search volume</span>
                <p class="title-reason">${t.reason}</p>
              </div>
            `).join('')}
          </div>
        ` : ''}

        ${s.best_recommendation ? `
          <div class="gen-section" style="margin-top: 16px;">
            <h5>🏆 Best Pick</h5>
            <p>${s.best_recommendation}</p>
          </div>
        ` : ''}
      </div>
    `;

    showAIResult(html);
  } catch (err) {
    showAIResult(`<div class="error-message"><h4>❌ Error</h4><p>${err.message}</p></div>`);
  }
}

